; gfxshow.asm - Display bitmap test images on RC702 screen
BDOS    EQU 0x0005
CONIN   EQU 1
DSPSTR  EQU 0xF800
SCRNSZ  EQU 1920

    .Z80
    ORG 0x0100

start:

    ld hl,img_smiley
    ld de,DSPSTR
    ld bc,SCRNSZ
    ldir
    ld c,CONIN
    call BDOS
    cp 0x1B
    jp z,exit

    ld hl,img_ghost
    ld de,DSPSTR
    ld bc,SCRNSZ
    ldir
    ld c,CONIN
    call BDOS
    cp 0x1B
    jp z,exit

    ld hl,img_house
    ld de,DSPSTR
    ld bc,SCRNSZ
    ldir
    ld c,CONIN
    call BDOS
    cp 0x1B
    jp z,exit

    ld hl,img_star
    ld de,DSPSTR
    ld bc,SCRNSZ
    ldir
    ld c,CONIN
    call BDOS
    cp 0x1B
    jp z,exit

    ld hl,img_cat
    ld de,DSPSTR
    ld bc,SCRNSZ
    ldir
    ld c,CONIN
    call BDOS
    cp 0x1B
    jp z,exit

    ld hl,img_rc_logo
    ld de,DSPSTR
    ld bc,SCRNSZ
    ldir
    ld c,CONIN
    call BDOS
    cp 0x1B
    jp z,exit

    jp start
exit:
    ld c,9
    ld de,clrmsg
    call BDOS
    rst 0
clrmsg:
    db 0x1B, 'E', '$'

